const raw = $json.output ?? $json.text ?? $json.message ?? $json;
let parsed = raw;

if (typeof raw === 'string') {
  const cleaned = raw
    .trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```$/i, '')
    .trim();

  parsed = JSON.parse(cleaned);
}

const hasChips = Array.isArray(parsed.chips) && parsed.chips.length > 0;

const hasCompletePost =
  parsed.post &&
  typeof parsed.post.title === 'string' &&
  parsed.post.title.trim() &&
  typeof parsed.post.content === 'string' &&
  parsed.post.content.trim() &&
  (
    parsed.post.colorKey ||
    parsed.post.color ||
    parsed.post.colorId ||
    parsed.post.freeColorName
  );

const isPostReadyStep = parsed.phase === 'post_ready';

// STEP 7: 글 카드가 나왔는데 chips가 없을 때만 보완
if (isPostReadyStep && hasCompletePost && !hasChips) {
  parsed.chips = [
    {
      label: '좋아',
      value: '좋아',
    },
    {
      label: '조금 더 대화하고 수정하기',
      value: '__refine__',
      action: 'refine',
    },
    {
      label: '직접 수정하기',
      value: '직접 수정하기',
      action: 'edit',
    },
    {
      label: '다시 처음부터 대화하기',
      value: '다시 처음부터 대화하기',
      action: 'restart',
    },
  ];
}

// STEP 8: 게시하기/임시저장 chips가 오면 action 보정
if (Array.isArray(parsed.chips)) {
  parsed.chips = parsed.chips.map((chip) => {
    if (typeof chip === 'string') {
      if (chip.includes('게시')) {
        return {
          label: chip,
          value: chip,
          action: 'publish',
        };
      }

      if (chip.includes('임시저장')) {
        return {
          label: chip,
          value: chip,
          action: 'save-draft',
        };
      }

      return {
        label: chip,
        value: chip,
      };
    }

    if (chip && typeof chip === 'object') {
      if (!chip.action && chip.label?.includes('게시')) {
        return {
          ...chip,
          action: 'publish',
        };
      }

      if (!chip.action && chip.label?.includes('임시저장')) {
        return {
          ...chip,
          action: 'save-draft',
        };
      }
    }

    return chip;
  });
}

return [{
  json: {
    message: parsed.message,
    ...(parsed.phase ? { phase: parsed.phase } : {}),
    ...(parsed.chips ? { chips: parsed.chips } : {}),
    ...(parsed.post ? { post: parsed.post } : {}),
  },
}];
